sql:
SELECT COUNT(*) AS successful_response_count
FROM response_logs
WHERE response_outcome = 'success' AND response_id = 1;

SELECT name
FROM fire_stations
WHERE status = 'active';

SELECT last_service_date
FROM station_services
WHERE station_id = 1 AND service_id = 1;

SELECT COUNT(station_id) AS active_stations_count
FROM fire_stations
WHERE status = 'active';

external_knowledge:
- 'Most recent' refers to the response with the latest date; 
- A 'successful response' means the response_outcome is 'success'; 
- 'Past year' refers to the period from the current date minus one year to the current date; 
- The 'top three' refers to the stations with the highest count of successful responses.

sql:
SELECT station_id, MAX(response_date) AS latest_response_date
FROM response_logs
GROUP BY station_id;

SELECT COUNT(*) AS total_services
FROM service_logs
WHERE station_id = 1;

SELECT name
FROM fire_stations
ORDER BY name;

SELECT COUNT(*) AS unsafe_checks
FROM bulk_water
WHERE station_id = 1 AND check_result = 'unsafe';

SELECT DISTINCT station_id
FROM response_logs
ORDER BY station_id;

SELECT name AS station_name
FROM fire_stations
ORDER BY station_name;
